const body = $('Webhook').item.json.body;
const data = body?.data;
if (!data) return [];

const remoteJid = data?.key?.remoteJid || '';
if (remoteJid.includes('@g.us')) return [];

const telefone = remoteJid.split('@')[0];
const nomeContato = data?.pushName || telefone;
const msg = data?.message || {};

const texto = (msg.conversation || msg.extendedTextMessage?.text || '').trim();

let tipoMensagem = 'texto';
let arquivoInfo = null;

if (msg.imageMessage) {
  tipoMensagem = 'arquivo';
  arquivoInfo = { mimetype: msg.imageMessage.mimetype || 'image/jpeg', extensao: 'jpg', nomeArquivo: `img_${Date.now()}.jpg` };
} else if (msg.documentMessage) {
  tipoMensagem = 'arquivo';
  const fname = msg.documentMessage.fileName || `doc_${Date.now()}.pdf`;
  arquivoInfo = { mimetype: msg.documentMessage.mimetype || 'application/pdf', extensao: fname.split('.').pop(), nomeArquivo: fname };
} else if (msg.audioMessage || msg.stickerMessage) {
  return [];
}

if (!texto && tipoMensagem === 'texto') return [];

return [{ json: { telefone, nomeContato, tipoMensagem, texto, arquivoInfo, messageKey: data.key, messageData: data.message } }];

const dadosMsg = $('Extrair Dados').item.json;
const cfg      = $('Configuração').item.json;
const telefone  = dadosMsg.telefone;
const nomeContato = dadosMsg.nomeContato;
const tipoMensagem = dadosMsg.tipoMensagem;
const texto = dadosMsg.texto || '';

// Pegar conversa do Supabase (pode ser array vazio)
let conversaRow = null;
try {
  const rows = $input.all();
  const found = rows.find(r => r.json?.telefone === telefone);
  if (found && found.json?.telefone) conversaRow = found.json;
} catch(e) {}

// Timeout de 10 minutos em aguardando_arquivos
const TIMEOUT_MS = 10 * 60 * 1000;
if (conversaRow?.estado === 'aguardando_arquivos') {
  const lastUpdate = new Date(conversaRow.updated_at).getTime();
  if (Date.now() - lastUpdate > TIMEOUT_MS) conversaRow = null;
}

// Conversa nova ou concluída → reiniciar
if (!conversaRow || conversaRow.estado === 'concluido') {
  const dadosIniciais = { historico: [], arquivos_pendentes: [], arquivos_coletados: [] };
  dadosIniciais.historico.push({ role: 'user', parts: [{ text: texto }] });

  const systemPrompt = `Você é Ana, assistente virtual da HealthPrevi, clínica especializada em laudos médicos periciais para processos do INSS, trabalhistas e de seguros, com atendimento presencial e online em todo o Brasil.\n\nSeu objetivo é coletar informações do paciente em ordem, UMA pergunta por mensagem:\n\n1. Nome completo\n2. Tipo de laudo (opções: auxílio-doença, auxílio-acidente / pecúlio, BPC/LOAS)\n3. Especialidade médica (ortopedista, clínico geral, psiquiatra, neurologista, outra)\n4. Se possui atestados médicos antigos relacionados ao caso (responda com true ou false no JSON)\n5. Se possui exames como raio-X, ressonância magnética, tomografia etc (true ou false)\n6. Se possui prontuário médico (true ou false)\n\nREGRAS:\n- UMA pergunta por mensagem, cordial e simples, máximo 3 linhas\n- Se a resposta for fora do contexto, redirecione gentilmente\n- Quando todas as 6 informações estiverem coletadas, envie uma mensagem dizendo que irá pedir os documentos em seguida e marque concluido como true\n- Responda SEMPRE em português do Brasil\n\nRETORNE APENAS este JSON, sem texto antes ou depois:\n{\n  \

: null\n  }\n}`;

  const geminiPayload = {
    systemInstruction: { parts: [{ text: systemPrompt }] },
    contents: dadosIniciais.historico,
    generationConfig: { temperature: 0.3, maxOutputTokens: 500 }
  };

  return [{ json: { acao: 'gemini', telefone, nomeContato, dadosAtuais: dadosIniciais, geminiPayload, geminiKey: cfg.gemini_key } }];
}

const estado = conversaRow.estado;
const dados = typeof conversaRow.dados === 'string' ? JSON.parse(conversaRow.dados) : (conversaRow.dados || {});
const historico = dados.historico || [];
const arquivosPendentes = dados.arquivos_pendentes || [];
const arquivosColetados = dados.arquivos_coletados || [];
const etapaAtual = conversaRow.etapa_arquivo || arquivosPendentes[0];

// ── ESTADO: qualificando ──────────────────────────────────────
if (estado === 'qualificando') {
  if (tipoMensagem === 'arquivo') {
    return [{ json: {
      acao: 'texto_simples', telefone, nomeContato,
      mensagemResposta: 'Obrigado! Vou pedir os documentos em breve. Primeiro preciso de mais algumas informações em texto. Pode continuar?',
      novoEstado: 'qualificando', novaEtapa: null, novosDados: dados, concluido: false, dadosLead: null
    }}];
  }

  historico.push({ role: 'user', parts: [{ text: texto }] });
  dados.historico = historico;

  const systemPrompt = `Você é Ana, assistente virtual da HealthPrevi, clínica especializada em laudos médicos periciais para processos do INSS, trabalhistas e de seguros, com atendimento presencial e online em todo o Brasil.\n\nSeu objetivo é coletar informações do paciente em ordem, UMA pergunta por mensagem:\n\n1. Nome completo\n2. Tipo de laudo (opções: auxílio-doença, auxílio-acidente / pecúlio, BPC/LOAS)\n3. Especialidade médica (ortopedista, clínico geral, psiquiatra, neurologista, outra)\n4. Se possui atestados médicos antigos relacionados ao caso (responda com true ou false no JSON)\n5. Se possui exames como raio-X, ressonância magnética, tomografia etc (true ou false)\n6. Se possui prontuário médico (true ou false)\n\nREGRAS:\n- UMA pergunta por mensagem, cordial e simples, máximo 3 linhas\n- Se a resposta for fora do contexto, redirecione gentilmente\n- Quando todas as 6 informações estiverem coletadas, envie uma mensagem dizendo que irá pedir os documentos em seguida e marque concluido como true\n- Responda SEMPRE em português do Brasil\n\nRETORNE APENAS este JSON, sem texto antes ou depois:\n{\n  \

: null\n  }\n}`;

  const geminiPayload = {
    systemInstruction: { parts: [{ text: systemPrompt }] },
    contents: historico,
    generationConfig: { temperature: 0.3, maxOutputTokens: 500 }
  };

  return [{ json: { acao: 'gemini', telefone, nomeContato, dadosAtuais: dados, geminiPayload, geminiKey: cfg.gemini_key } }];
}

// ── ESTADO: aguardando_arquivos ───────────────────────────────
if (estado === 'aguardando_arquivos') {
  if (tipoMensagem === 'arquivo') {
    return [{ json: {
      acao: 'arquivo', telefone, nomeContato, etapaAtual,
      arquivosPendentes, arquivosColetados, dados,
      arquivoInfo: dadosMsg.arquivoInfo,
      messageKey: dadosMsg.messageKey,
      messageData: dadosMsg.messageData
    }}];
  }

  // Texto recebido durante coleta de arquivos
  const idxAtual = arquivosPendentes.indexOf(etapaAtual);
  const restantes = arquivosPendentes.slice(idxAtual + 1);

  const msgs = {
    atestados: 'Perfeito! Agora, você tem exames como raio-X, ressonância ou tomografia? Se tiver, pode enviar aqui.',
    exames: 'Ótimo! Por último: você tem prontuário médico? Se tiver, pode enviar.',
    prontuario: null
  };

  if (restantes.length > 0) {
    const proximo = restantes[0];
    return [{ json: {
      acao: 'texto_simples', telefone, nomeContato,
      mensagemResposta: msgs[etapaAtual] || 'Entendido! Pode enviar o próximo documento?',
      novoEstado: 'aguardando_arquivos', novaEtapa: proximo,
      novosDados: dados, concluido: false, dadosLead: null
    }}];
  }

  // Sem mais arquivos pendentes → concluir
  const dadosLead = {
    telefone, nome_contato_wa: nomeContato,
    nome: dados.nome || null, tipo_laudo: dados.tipo_laudo || null,
    especialidade: dados.especialidade || null,
    tem_atestados: !!dados.tem_atestados,
    tem_exames: !!dados.tem_exames,
    tem_prontuario: !!dados.tem_prontuario
  };

  return [{ json: {
    acao: 'texto_simples', telefone, nomeContato,
    mensagemResposta: 'Perfeito! Recebemos tudo. A equipe da HealthPrevi entrará em contato em breve para agendar sua consulta. 😊',
    novoEstado: 'concluido', novaEtapa: null,
    novosDados: dados, concluido: true, dadosLead
  }}];
}

return [{ json: { acao: 'texto_simples', telefone, nomeContato, mensagemResposta: 'Olá! Como posso ajudar?', novoEstado: 'qualificando', novaEtapa: null, novosDados: {}, concluido: false, dadosLead: null } }];

const geminiText = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
const ctx = $('Processar Decisão').item.json;
const { telefone, nomeContato, dadosAtuais } = ctx;

let parsed;
try {
  const match = geminiText.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : geminiText);
} catch(e) {
  parsed = { mensagem: 'Desculpe, tive um problema. Pode repetir?', concluido: false, dados: {} };
}

const mensagem   = parsed.mensagem || 'Pode repetir?';
const concluido  = parsed.concluido === true;
const dadosGemini = parsed.dados || {};

const historico = dadosAtuais.historico || [];
historico.push({ role: 'model', parts: [{ text: geminiText }] });

const dadosAtualizados = { ...dadosAtuais, historico };
for (const [k, v] of Object.entries(dadosGemini)) {
  if (v !== null && v !== undefined) dadosAtualizados[k] = v;
}

let novoEstado = 'qualificando';
let novaEtapa  = null;
let dadosLead  = null;

if (concluido) {
  const pendentes = [];
  const ta = dadosAtualizados.tem_atestados;
  const te = dadosAtualizados.tem_exames;
  const tp = dadosAtualizados.tem_prontuario;
  if (ta === true  || ta === 'true'  || ta === 'sim'  || ta === 'Sim')  pendentes.push('atestados');
  if (te === true  || te === 'true'  || te === 'sim'  || te === 'Sim')  pendentes.push('exames');
  if (tp === true  || tp === 'true'  || tp === 'sim'  || tp === 'Sim')  pendentes.push('prontuario');

  dadosAtualizados.arquivos_pendentes = pendentes;
  dadosAtualizados.arquivos_coletados = [];

  if (pendentes.length > 0) {
    novoEstado = 'aguardando_arquivos';
    novaEtapa  = pendentes[0];
    // Emenda na mensagem do Gemini para pedir o primeiro arquivo
    const primeraMsgs = { atestados: ' Pode me enviar seus atestados médicos agora?', exames: ' Pode me enviar seus exames agora?', prontuario: ' Pode me enviar seu prontuário médico?' };
  } else {
    novoEstado = 'concluido';
    dadosLead = { telefone, nome_contato_wa: nomeContato, nome: dadosAtualizados.nome || null, tipo_laudo: dadosAtualizados.tipo_laudo || null, especialidade: dadosAtualizados.especialidade || null, tem_atestados: false, tem_exames: false, tem_prontuario: false };
  }
}

return [{ json: { telefone, nomeContato, mensagemResposta: mensagem, novoEstado, novaEtapa, novosDados: dadosAtualizados, concluido: novoEstado === 'concluido', dadosLead } }];

const base64   = $json.base64;
const mimetype = $json.mimetype || 'application/octet-stream';
const ctx      = $('Processar Decisão').item.json;
const { telefone, etapaAtual, arquivoInfo } = ctx;

const ext      = arquivoInfo?.extensao || 'bin';
const fname    = arquivoInfo?.nomeArquivo || `arquivo_${Date.now()}.${ext}`;
const storagePath = `${telefone}/${etapaAtual}/${fname}`;

return [{
  json: { telefone, mimetype, storagePath, fname, etapaAtual },
  binary: { data: { data: base64, mimeType: mimetype, fileName: fname } }
}];

const ctx = $('Processar Decisão').item.json;
const { telefone, nomeContato, etapaAtual, arquivosPendentes, arquivosColetados, dados } = ctx;

const coletados = [...(arquivosColetados || []), etapaAtual];
const idxAtual  = (arquivosPendentes || []).indexOf(etapaAtual);
const restantes = (arquivosPendentes || []).slice(idxAtual + 1);

dados.arquivos_coletados = coletados;

const msgs = {
  atestados:  'Atestado recebido! Agora, você tem exames como raio-X, ressonância ou tomografia? Se tiver, pode enviar aqui.',
  exames:     'Exames recebidos! Por último: você tem prontuário médico? Se tiver, pode enviar.',
  prontuario: null
};

if (restantes.length > 0) {
  const proximo = restantes[0];
  return [{ json: {
    telefone, nomeContato,
    mensagemResposta: msgs[etapaAtual] || 'Documento recebido! Pode enviar o próximo?',
    novoEstado: 'aguardando_arquivos', novaEtapa: proximo,
    novosDados: dados, concluido: false, dadosLead: null
  }}];
}

// Último arquivo recebido → concluir
const dadosLead = {
  telefone, nome_contato_wa: nomeContato,
  nome: dados.nome || null, tipo_laudo: dados.tipo_laudo || null,
  especialidade: dados.especialidade || null,
  tem_atestados: (dados.arquivos_coletados || []).includes('atestados'),
  tem_exames:    (dados.arquivos_coletados || []).includes('exames'),
  tem_prontuario:(dados.arquivos_coletados || []).includes('prontuario')
};

return [{ json: {
  telefone, nomeContato,
  mensagemResposta: 'Perfeito! Recebemos todos os documentos. A equipe da HealthPrevi entrará em contato em breve para agendar sua consulta.',
  novoEstado: 'concluido', novaEtapa: null,
  novosDados: dados, concluido: true, dadosLead
}}];
